export const ooHeroExpWater: SharedOoRow[] = [{"id":"surf-clinic-heats","name":"Learn-to-Surf Clinic & Sunset Heats","kind":"water","intensity":"active","summary":"A morning beach clinic gets total beginners standing up in the whitewater within an hour; by the afternoon the group splits into bracketed 'heats' for a friendly contest scored on first-wave-up and best ride. Real surf schools run 4:1 instructor ratios and have handled 250-person corporate groups (Manly Surf School / Sun Microsystems), so a 200-person company can rotate through in timed waves on a wide beach break.","whyItBonds":"Nobody is good at it on day one, so the CEO wipes out next to the new analyst — the great equalizer. Cheering a colleague onto their first wave is pure, unguarded celebration.","groupRange":{"min":20,"max":250},"scaleNote":"Wide beach break + 4:1 instructor ratio. Group is split into rolling 90-minute waves of 40–60; boards and rash guards pre-staged in numbered lanes. Heats bracket the group into teams; live leaderboard on the sand. 200+ needs a 600m+ beach and a second school's instructor pool.","duration":"Half day","pricePerPerson":{"low":120,"high":225},"pairsWith":["coastal","tropical","island"],"regionsHint":"Costa Rica (Tamarindo/Nosara), Hawaii (North Shore Oahu), Portugal (Algarve), San Diego, Byron Bay/Manly AUS, Sayulita MX","tags":["beginner-friendly","beach","contest","equalizer","sunset"],"imageQuery":"corporate group beginner surf lesson lineup beach instructors tropical","sites":["offsite"],"wizards":["offsite-retreat","offsite-outing"],"products":["retreat","outing"],"audiences":["corporate","clients","internal"]},{"id":"discover-dive-reef-conservation","name":"Discover Diving & Reef Conservation Day","kind":"water","intensity":"active","summary":"A PADI Discover Scuba session takes non-certified guests on their first ocean breath in shallow reef; certified divers and snorkelers join a hands-on coral-restoration dive (out-planting nursery fragments, REEF fish survey). Operators like Coral Restoration Foundation and REEF run structured group programs, and the conservation log gives the day a tangible 'we left it better' outcome.","whyItBonds":"Shared first-breath nerves underwater forge trust fast, and planting coral the group can revisit gives a team a literal living legacy from the offsite — not a swag bag.","groupRange":{"min":20,"max":150},"scaleNote":"Dive-boat fleet (6–8 divers per boat) running shuttle rotations from one mooring; non-divers run parallel snorkel-and-survey flotilla. 150 needs a multi-boat operator and staggered tide windows. Conservation component capped by reef-permit numbers — split into AM/PM relays.","duration":"Full day","pricePerPerson":{"low":250,"high":450},"pairsWith":["tropical","island","coastal"],"regionsHint":"Florida Keys (Key Largo), Bonaire, Cozumel MX, Great Barrier Reef (Cairns), Roatán Honduras, Maldives","tags":["scuba","snorkel","conservation","legacy","marine"],"imageQuery":"scuba divers coral restoration reef planting group tropical clear water","sites":["offsite"],"wizards":["offsite-retreat","offsite-outing"],"products":["retreat","outing"],"audiences":["corporate","clients","internal"]},{"id":"photo-safari-spotlist-cup","name":"Photographic Safari — The Spot List Cup","kind":"wildlife","intensity":"active","summary":"Open 4x4 game vehicles fan out across a private reserve at dawn, each team racing a 'spot list' — Big Five plus rare birds and behaviors — scored by photos verified back at camp over sundowners. Reserves like Madikwe, Sabi Sand and Welgevonden run fleets of guided vehicles (6–9 guests each), so a 100-person group splits into a convoy of competing trucks across tens of thousands of hectares.","whyItBonds":"A shared adrenaline gasp at a leopard ten feet away, then the campfire argument over whose photo counts — competitive but reverent, and the stories outlast every slide deck.","groupRange":{"min":18,"max":120},"scaleNote":"Vehicle convoy: 1 guide + 6–9 guests per 4x4; a 100-person group = ~12–15 trucks, requiring a reserve large enough to space them (Madikwe 75,000ha, Welgevonden 37,000ha) plus a multi-lodge buyout. Spot-list scored digitally at camp; AM and PM drives = two rounds.","duration":"Full day","pricePerPerson":{"low":600,"high":1800},"pairsWith":["safari","countryside"],"regionsHint":"South Africa (Madikwe/Sabi Sand/Welgevonden), Botswana (Okavango), Kenya (Maasai Mara), Tanzania (Serengeti)","tags":["big-five","game-drive","photography","competition","spot-list","sundowner"],"imageQuery":"open safari vehicle convoy guests photographing elephants golden hour African reserve","sites":["offsite"],"wizards":["offsite-retreat","offsite-outing"],"products":["retreat","outing"],"audiences":["corporate","clients","internal"]},{"id":"catamaran-island-flotilla","name":"Catamaran Island Day — The Flotilla","kind":"water","intensity":"spirited","summary":"A fleet of crewed catamarans sails the group island-to-island — swim stops at a hidden cove, a beach-club lunch on an uninhabited cay, snorkel gear aboard. Crewed catamarans run ~8–12 guests each ($425–625 pp/day Caribbean crewed rates), so a fleet of 10–20 boats moves 150–250 people as one synchronized flotilla.","whyItBonds":"Boat crews self-organize — someone rigs the music, someone captains the swim, someone plates the lunch. By the second cove the boat is a crew, not a roster.","groupRange":{"min":24,"max":250},"scaleNote":"Catamaran fleet: 8–12 guests per crewed cat; 200 people = ~18–20 boats moving as a flotilla with a lead vessel and radio coordination. Anchorage and beach-club capacity at the island stop is the real limiter — book exclusive-use cays.","duration":"Full day","pricePerPerson":{"low":300,"high":650},"pairsWith":["island","tropical","coastal"],"regionsHint":"BVI, Croatia (Hvar/Split), Greek Cyclades, St. Barths/St. Martin, Belize cayes, Whitsundays AUS","tags":["sailing","island-hop","swim","fleet","beach-club"],"imageQuery":"fleet of catamarans anchored turquoise cove guests swimming island day","sites":["offsite"],"wizards":["offsite-retreat","offsite-outing"],"products":["retreat","outing"],"audiences":["corporate","clients","internal"]},{"id":"canopy-waterfall-rappel","name":"Jungle Canopy & Waterfall Rappel Circuit","kind":"wilderness","intensity":"adventurous","summary":"A timed adventure circuit through the rainforest canopy — multi-cable zipline runs (some courses cross 11+ waterfalls), a Tarzan swing, and a guided rappel down a live waterfall. Costa Rican adventure parks run continuous-flow zipline operations built for steady throughput, so large groups rotate through stations in staggered start waves.","whyItBonds":"The pause at the rappel lip — talking a nervous teammate over the edge — is the trust fall made real. Adrenaline shared at altitude bonds harder than any conference-room exercise.","groupRange":{"min":20,"max":200},"scaleNote":"Station-circuit with staggered starts: groups of 12–16 launch every 10–15 min across zipline, swing and rappel stations to avoid bottlenecks. 200 needs a multi-line course (18-cable parks exist) and a full-park buyout; slower/non-rappel guests route to a parallel canopy walk.","duration":"Half day","pricePerPerson":{"low":110,"high":230},"pairsWith":["tropical","countryside"],"regionsHint":"Costa Rica (Arenal/Monteverde/Jaco), Costa Rica Osa, Dominican Republic, Bali, Costa Rica Manuel Antonio","tags":["zipline","rappel","waterfall","rainforest","adrenaline"],"imageQuery":"group ziplining over rainforest waterfall canopy Costa Rica harness","sites":["offsite"],"wizards":["offsite-retreat","offsite-outing"],"products":["retreat","outing"],"audiences":["corporate","clients","internal"]},{"id":"surf-yoga-sunrise","name":"Surf & Yoga Sunrise Block","kind":"wellness","intensity":"active","summary":"A dawn block pairing a beach yoga and breathwork session with a guided surf session — the format perfected by Costa Rica and Nicaragua surf-wellness camps (Surf Synergy, Costa Dulce). Active and grounding rather than spa-passive: the group moves together, then takes the energy into the water as the sun comes up.","whyItBonds":"Doing something physical and slightly humbling at sunrise, before phones and agendas, resets a team's nervous system together — the rare offsite block people describe as 'I needed that.'","groupRange":{"min":20,"max":120},"scaleNote":"Beach yoga shala or open sand seats the full group for breathwork; surf then runs in waves of 40–60 at 4:1 ratio (see surf clinic). Non-surfers continue with a longer flow or a coastal walk. Sunrise tide window caps the surf rotation count — best as a recurring daily ritual across a multi-day retreat.","duration":"Half day","pricePerPerson":{"low":90,"high":180},"pairsWith":["coastal","tropical","island"],"regionsHint":"Costa Rica (Nosara/Santa Teresa), Nicaragua (Popoyo), Portugal (Algarve), Morocco (Taghazout), Sri Lanka, Bali","tags":["yoga","breathwork","surf","sunrise","wellness","active-recovery"],"imageQuery":"beach sunrise yoga group on sand surfboards ocean tropical","sites":["offsite"],"wizards":["offsite-retreat","offsite-outing"],"products":["retreat","outing"],"audiences":["corporate","clients","internal"]}];

