export const ooHeroExpWinter: SharedOoRow[] = [{"id":"winter-company-cup-gs","name":"The Company Cup — Giant Slalom Race","kind":"winter","intensity":"active","summary":"A full corporate ski race run on the NASTAR National Standard system: a dual-gate giant slalom course on a closed resort run, electronic timing, printed bibs, live leaderboard, and a real podium with platinum/gold/silver handicap medals. Every skill level competes fairly against a pacesetter handicap, so the marketing manager who skis twice a year can out-medal the VP. Closes with an awards après on the deck.","whyItBonds":"A handicap-normalized race is the rare competition where total beginners and ex-racers share one leaderboard — everyone has skin in it, everyone watches everyone's run, and the team that cheers loudest from the fence becomes the story of the trip.","groupRange":{"min":30,"max":400},"scaleNote":"Run as timed heats down a dual course (two gates side-by-side) on a roped-off race trail; resort race departments at Aspen Snowmass, Copper Mountain, Deer Valley, Schweitzer and Crystal Mountain run NASTAR daily and seed large fields into waves by bib. 400 racers = staggered start windows across a morning/afternoon, with a non-racing 'spectator village' at the finish (heated tent, cocoa/cocktails). Best-time-per-department scoring keeps non-experts engaged.","duration":"Half day (race) or Full day (clinic + race)","pricePerPerson":{"low":95,"high":350},"pairsWith":["alpine","ski-resort","countryside"],"regionsHint":"US Rockies (Aspen/Snowmass, Copper, Deer Valley CO/UT), Schweitzer ID, Crystal Mountain MI; equivalents at most lift-served resorts in the Alps and NZ","tags":["race","timed","podium","handicap","skill-inclusive","spectator-friendly","alpine"],"imageQuery":"NASTAR giant slalom race course dual gates skier bib resort","sites":["offsite"],"wizards":["offsite-retreat","offsite-outing"],"products":["retreat","outing"],"audiences":["corporate","clients","internal"]},{"id":"winter-heli-cat-powder-drop","name":"Powder Drop — Heli & Cat Skiing Day","kind":"winter","intensity":"adventurous","summary":"Untracked backcountry powder for the able-skiing core of the group: helicopter or snowcat lifts into private alpine terrain, guided in small ability-matched pods by certified mountain guides, with a hot lunch in the powder and avalanche-safety briefing first. CMH (Canadian Mountain Holidays) and Eagle Pass run single-day heli ops out of BC; Mustang Powder and Selkirk run snowcat days for groups who want the same powder at half the price and zero rotor noise.","whyItBonds":"Sharing the first turns on an untouched face — and the nervous chairlift-of-the-sky ride up — forges a different bond than any conference room. Small fixed pods mean the same 4–11 people ski, eat and high-five together all day.","groupRange":{"min":12,"max":88},"scaleNote":"Heli pods seat ~4 skiers/guide; cat cabins seat ~12. Scale by running multiple machines in parallel fleets and staggering basecamp departures — a full company splits into an advanced heli/cat track (powder) and an intermediate resort-race or snowshoe track so non-experts aren't stranded. Mustang Powder's lodge handles 32 cat guests; multi-cat days push past 50. Strong weather contingency required.","duration":"Full day","pricePerPerson":{"low":950,"high":2200},"pairsWith":["alpine","ski-resort"],"regionsHint":"British Columbia (CMH Revelstoke/Valemount/Purcell, Eagle Pass, Mustang Powder, Selkirk); Niseko cat skiing (Iwanai) JP; Queenstown/Wānaka NZ (Harris Mountains, Alpine Heliski) for southern-winter Jun–Sep","tags":["heli-ski","cat-ski","powder","backcountry","guided","advanced","bucket-list"],"imageQuery":"heli-skiing helicopter powder snow British Columbia group skiers","sites":["offsite"],"wizards":["offsite-retreat","offsite-outing"],"products":["retreat","outing"],"audiences":["corporate","clients","internal"]},{"id":"winter-biathlon-relay","name":"The Winter Biathlon — Ski & Shoot Relay","kind":"winter","intensity":"active","summary":"The Olympic team event, made corporate-safe: teams cross-country ski (or snowshoe) a loop, then drop to the mat to fire laser or air rifles at knock-down targets, with a penalty loop for every miss. No bullets — laser-rifle programs (now standard at US Nordic centers and at venues like Devil's Thumb Ranch, CO and Snow Mountain Ranch) make it injury-free and runnable year-round on any flat snowfield. Steady hands plus burning lungs equals comedy and genuine pressure.","whyItBonds":"Biathlon is the perfect physiology-of-teamwork lesson: you must sprint, then instantly calm your heart rate to shoot. Relay format means a slow skier and a steady shot need each other — and the penalty-loop tension makes every team's anchor leg a spectator event.","groupRange":{"min":20,"max":300},"scaleNote":"Run as a rotating relay across multiple parallel shooting lanes (8–10 mats) and several short ski loops, seeding teams of 4–6 into start waves every few minutes. Laser rifles need no berm or range safety officer, so the lane count scales with mats and instructors, not real estate; large fields cycle through a heated team tent between legs. Devil's Thumb Ranch and Nordic centers in CO/UT/WI run turnkey corporate versions.","duration":"Half day","pricePerPerson":{"low":110,"high":260},"pairsWith":["countryside","alpine","ski-resort","lake"],"regionsHint":"Colorado (Devil's Thumb Ranch, Snow Mountain Ranch/YMCA of the Rockies, Soldier Hollow UT), Wisconsin (Birkie/Ariens range), Scandinavia & Alps Nordic centers","tags":["biathlon","relay","cross-country","laser-rifle","team-event","skill-inclusive","precision"],"imageQuery":"biathlon laser rifle shooting mat cross country ski targets winter","sites":["offsite"],"wizards":["offsite-retreat","offsite-outing"],"products":["retreat","outing"],"audiences":["corporate","clients","internal"]},{"id":"winter-arctic-ice-drive","name":"Arctic Ice Drive — Cars & Karts on Ice","kind":"winter","intensity":"adventurous","summary":"Studded-tire supercars and rally cars (600+ metal studs per tire) drifting controlled lines on groomed tracks plowed into a frozen Arctic lake — the format Lapland Ice Driving runs on a 3,000-acre private domain in Arjeplog, Swedish Lapland. Pros coach car control and counter-steer before timed sessions; an ice-kart Grand Prix gives non-drivers and the speed-shy their own heats. February ice, midday Arctic light, fleet of 30+ prepared cars.","whyItBonds":"Nothing equalizes a room like everyone learning to drift at 5 mph and laughing through the spins — then the timed kart GP turns the whole company into pit crews and rivals. Shared adrenaline and a leaderboard, on a lake, under the northern sky.","groupRange":{"min":20,"max":150},"scaleNote":"Multiple tracks plowed in parallel on the lake run simultaneously: a supercar/rally circuit, an ice-kart GP oval, and a skills/gymkhana pad, with the group rotating in fleets between stations and a heated lodge for downtime. Car fleets of 30+ at Arjeplog support large rotations; the Andros-style format scales by adding tracks and instructors, not waiting in a single line.","duration":"Full day (or half day)","pricePerPerson":{"low":700,"high":2500},"pairsWith":["lake","alpine","countryside"],"regionsHint":"Swedish Lapland (Arjeplog — Lapland Ice Driving), Finnish Lapland; Alpine ice circuits (Flaine/Serre Chevalier FR); season ~Jan–mid-Mar","tags":["ice-driving","motorsport","supercars","ice-karting","frozen-lake","drifting","arctic"],"imageQuery":"supercar ice driving frozen lake Lapland studded tires drift snow","sites":["offsite"],"wizards":["offsite-retreat","offsite-outing"],"products":["retreat","outing"],"audiences":["corporate","clients","internal"]},{"id":"winter-husky-expedition","name":"The Husky Expedition — Drive Your Own Sled","kind":"winter","intensity":"active","summary":"Not a passenger ride — each pair gets their own harnessed husky team to drive across the Lapland fjell, after a mushing lesson and dog-care briefing. Operators like heyHusky and Jokkmokkguiderna (Swedish Lapland) and Hetta Huskies (Finland) run multi-sled convoys where everyone takes a turn on the runners, finishing at a fireside lavvu for hot lingonberry and reindeer stew. In the US, Krabloonik (Aspen/Snowmass) runs the closest equivalent.","whyItBonds":"Standing on the runners of your own team — feeling the dogs read your nerve — is humbling and exhilarating; pairs swap driver/passenger and learn fast that calm leadership moves the sled. The convoy crests a frozen lake together and nobody stops talking about it.","groupRange":{"min":16,"max":120},"scaleNote":"Scales by stacking departure waves and pooling sleds across kennels: a single operator runs ~10–25 at once, so 50–120 splits into morning/afternoon convoys with non-driving members at a warming hut (cocoa, kennel tour, photos) between rotations. heyHusky aggregates kennels across Lapland for incentive groups; pair with snowmobiling or a sauna to fill the day.","duration":"Half day","pricePerPerson":{"low":220,"high":650},"pairsWith":["alpine","countryside","lake"],"regionsHint":"Swedish & Finnish Lapland (heyHusky, Jokkmokkguiderna, Hetta Huskies), Norway (Tromsø); Aspen/Snowmass CO (Krabloonik); Canadian Rockies & Québec","tags":["dog-sledding","mushing","huskies","lapland","drive-your-own","arctic","pairs"],"imageQuery":"dog sledding husky team driver runners snow Lapland convoy","sites":["offsite"],"wizards":["offsite-retreat","offsite-outing"],"products":["retreat","outing"],"audiences":["corporate","clients","internal"]}];

